                  <div className="flex items-center justify-between text-xs">
                    <span className="text-white/40">Stint</span>
                    <span className="text-white/70">{strategy?.currentStint || 1}/{strategy?.totalStints || 3}</span>
                  </div>
                </div>
              </div>

              <motion.button
                whileHover={{ scale: 1.01 }}
                whileTap={{ scale: 0.99 }}
