export const ReplaySnapshot = () => {
  const { raceState, player, allCompetitors, chartData } = useRace();
  const [snapshots, setSnapshots] = useState([]);
  const [selectedSnapshot, setSelectedSnapshot] = useState(null);
  const [autoCapture, setAutoCapture] = useState(true);

  // Auto-capture on significant events
  React.useEffect(() => {
    if (!autoCapture || !raceState.isRunning) return;

    // Capture on pit stops, position changes, or every 5 laps
    const shouldCapture = 
      raceState.currentLap % 5 === 0 ||
      raceState.lifecycleStatus === 'PITTING';

    if (shouldCapture && raceState.currentLap > 0) {
      const existingSnapshot = snapshots.find(s => s.lap === raceState.currentLap);
      if (!existingSnapshot) {
        captureSnapshot();
      }
    }
  }, [raceState.currentLap, raceState.lifecycleStatus, autoCapture, raceState.isRunning]);

  const captureSnapshot = useCallback(() => {
    const newSnapshot = {
      id: `snapshot_${Date.now()}`,
      lap: raceState.currentLap,
      timestamp: new Date().toLocaleTimeString(),
      description: getSnapshotDescription(raceState, player),
      data: {
        position: player?.position,
        lapTime: player?.lapTime,
        tire: player?.tire,
        tireAge: player?.tireAge,
        gapToLeader: player?.gapToLeader,
        competitors: allCompetitors.slice(0, 5).map(c => ({
          position: c.position,
          driver: c.driver || c.name,
          gap_to_leader: c.gap_to_leader || c.gapToLeader,
        })),
        chartDataPoint: chartData[chartData.length - 1],
      },
    };

    setSnapshots(prev => [newSnapshot, ...prev].slice(0, 20)); // Keep last 20
  }, [raceState, player, allCompetitors, chartData]);

  const deleteSnapshot = useCallback((id) => {
    setSnapshots(prev => prev.filter(s => s.id !== id));
  }, []);

  const exportSnapshot = useCallback((snapshot) => {
    const dataStr = JSON.stringify(snapshot, null, 2);
    const dataBlob = new Blob([dataStr], { type: 'application/json' });
    const url = URL.createObjectURL(dataBlob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `f1-snapshot-lap-${snapshot.lap}-${Date.now()}.json`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  }, []);

  const getSnapshotDescription = (raceState, player) => {
    if (raceState.lifecycleStatus === 'PITTING') return 'Pit stop recorded';
    if (player?.position === 1) return 'Leading the race';
    if (raceState.safetyCarActive) return 'Safety Car period';
    return `Lap ${raceState.currentLap} - Race progress`;
  };

  return (
    <div className="f1-card">
      <div className="p-4 pb-3 flex items-center justify-between border-b border-white/[0.06]">
        <div className="flex items-center gap-3">
          <div className="w-9 h-9 bg-white/[0.04] rounded-xl flex items-center justify-center border border-white/[0.06]">
            <Camera className="w-4 h-4 text-purple-400/60" />
          </div>
          <div>
            <h3 className="text-sm font-bold text-white/70">Replay Snapshots</h3>
            <p className="text-[10px] text-white/20 uppercase tracking-wider">Auto-captured moments</p>
          </div>
        </div>

        <div className="flex items-center gap-2">
          <button
            onClick={captureSnapshot}
            disabled={!raceState.isRunning}
            className="p-2 bg-white/[0.03] hover:bg-white/[0.06] disabled:opacity-30 rounded-lg border border-white/[0.06] transition-colors"
            title="Capture Now"
          >
            <Camera className="w-4 h-4 text-white/50" />
          </button>

          <button
            onClick={() => setAutoCapture(!autoCapture)}
            className={`p-2 rounded-lg border transition-colors ${
              autoCapture 
                ? 'bg-emerald-500/10 border-emerald-500/20' 
                : 'bg-white/[0.03] border-white/[0.06]'
            }`}
            title={autoCapture ? 'Auto-capture ON' : 'Auto-capture OFF'}
          >
            <Activity className={`w-4 h-4 ${autoCapture ? 'text-emerald-400' : 'text-white/30'}`} />
          </button>
        </div>
      </div>

      <div className="p-3 space-y-2 max-h-64 overflow-y-auto">
        <AnimatePresence mode="popLayout">
          {snapshots.length === 0 ? (
            <motion.div
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              className="text-center py-8"
            >
              <Camera className="w-8 h-8 text-white/[0.08] mx-auto mb-2" />
              <p className="text-white/15 text-xs uppercase tracking-wider">No snapshots yet</p>
              <p className="text-white/10 text-[10px] mt-1">
                {raceState.isRunning ? 'Capturing automatically...' : 'Start race to capture'}
              </p>
            </motion.div>
          ) : (
            <>
              {snapshots.slice(0, 5).map((snapshot, index) => (
                <SnapshotCard
                  key={snapshot.id}
                  snapshot={snapshot}
                  index={index}
                  onLoad={setSelectedSnapshot}
                  onDelete={deleteSnapshot}
                />
              ))}

              {snapshots.length > 5 && (
                <p className="text-center text-[10px] text-white/20 pt-2">
                  +{snapshots.length - 5} more snapshots
                </p>
              )}
            </>
          )}
        </AnimatePresence>
      </div>

      <div className="px-3 py-2 border-t border-white/[0.06] flex items-center justify-between text-[10px]">
        <span className="text-white/20">
          {snapshots.length} snapshot{snapshots.length !== 1 ? 's' : ''}
        </span>
        <span className="text-white/15">
          {autoCapture ? 'Auto-capturing' : 'Manual mode'}
        </span>
      </div>

      <AnimatePresence>
        {selectedSnapshot && (
          <SnapshotDetail
            snapshot={selectedSnapshot}
            onClose={() => setSelectedSnapshot(null)}
            onExport={exportSnapshot}
          />
        )}
      </AnimatePresence>
    </div>
  );
};

export default memo(ReplaySnapshot);

import React, { useMemo, memo } from 'react';
import { motion } from 'framer-motion';
import {
  Line,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  ResponsiveContainer,
  ComposedChart,
  ReferenceLine,
} from 'recharts';
import { Activity, AlertCircle } from 'lucide-react';
import { useRace } from '../../context/RaceContext';
import AnimatedValue from '../common/AnimatedValue';

const generateFallbackData = (laps = 50) => {
  return Array.from({ length: laps }, (_, i) => ({
    lap: i + 1,
    '1-Stop': 90 + i * 0.08 + Math.sin(i * 0.2) * 0.5,
    '2-Stop': 90.2 + i * 0.06 + Math.sin(i * 0.15) * 0.4,
    'Aggressive': 89.8 + i * 0.1 + Math.sin(i * 0.25) * 0.6,
    isPrediction: false,
  }));
};

const CustomTooltip = memo(({ active, payload, label }) => {
  if (!active || !payload || payload.length === 0) return null;
  return (
    <div className="bg-[#0c0c0c]/95 border border-white/[0.08] rounded-lg p-3 shadow-[0_8px_24px_rgba(0,0,0,0.5)] backdrop-blur-sm">
      <p className="text-white/30 text-[10px] mb-2 font-mono uppercase tracking-wider">Lap {label}</p>
      {payload.map((entry, index) => {
        if (entry.name?.includes('prediction') || entry.dataKey?.includes('Ghost')) return null;
        return (
          <p key={index} className="text-xs font-mono flex items-center gap-2" style={{ color: entry.color }}>
            <span className="w-2 h-2 rounded-full" style={{ backgroundColor: entry.color }} />
            {entry.name}: {typeof entry.value === 'number' ? entry.value.toFixed(2) : entry.value}s
          </p>
        );
      })}
    </div>
  );
});
CustomTooltip.displayName = 'CustomTooltip';

const STRATEGY_CONFIG = {
  '1-Stop': { color: '#eab308', dashArray: '0', width: 3 },
  '2-Stop': { color: '#10b981', dashArray: '0', width: 3 },
  'Aggressive': { color: '#ef4444', dashArray: '5 5', width: 2 },
  'Conservative': { color: '#3b82f6', dashArray: '5 5', width: 2 },
  'AI-RL': { color: '#a855f7', dashArray: '0', width: 3 },
};

export const SimulationChart = ({ data, strategies, pitStops }) => {
  const { raceState, lapHistory, predictions, chartData: contextChartData } = useRace();

  const chartData = useMemo(() => {
    const baseData = (data && data.length > 0) ? data : 
                     (contextChartData && contextChartData.length > 0) ? contextChartData :
                     generateFallbackData(raceState.totalLaps || 50);
    return baseData.map((point, idx) => ({
      ...point,
      isPrediction: lapHistory.length > 0 && idx >= lapHistory.length,
      hasActual: lapHistory.length > 0 && idx < lapHistory.length,
    }));
  }, [data, lapHistory, predictions, raceState.currentLap, raceState.totalLaps, contextChartData]);

  const activeStrategies = useMemo(() => {
    if (!chartData || chartData.length === 0) return [];
    const firstPoint = chartData[0];
    return Object.keys(firstPoint)
      .filter(key => key !== 'lap' && key !== 'isPrediction' && key !== 'hasActual' && !key.includes('prediction') && !key.includes('Ghost'))
      .map((key, idx) => ({
        key,
        name: key,
        color: STRATEGY_CONFIG[key]?.color || ['#e10600', '#00d4ff', '#fbbf24', '#10b981'][idx % 4],
        dashArray: STRATEGY_CONFIG[key]?.dashArray || '0',
        width: STRATEGY_CONFIG[key]?.width || 2,
      }));
  }, [chartData]);

  const yDomain = useMemo(() => {
    if (!chartData || chartData.length === 0) return [85, 95];
    const allValues = chartData.flatMap(d => activeStrategies.map(s => d[s.key]).filter(v => v !== undefined && v !== null));
    if (allValues.length === 0) return [85, 95];
    const min = Math.min(...allValues);
    const max = Math.max(...allValues);
    return [Math.max(70, min - 3), max + 3];
  }, [chartData, activeStrategies]);

  const currentLap = raceState.currentLap || (lapHistory?.length || 0);

  if (!chartData || chartData.length === 0) {
    return (
      <div className="relative">
        <div className="p-5 pb-4 flex items-center gap-3">
          <div className="w-10 h-10 bg-white/[0.04] rounded-xl flex items-center justify-center border border-white/[0.06]">
            <Activity className="w-4 h-4 text-[#e10600]/60" />
          </div>
          <div>
            <h3 className="text-sm font-bold text-white/70">Strategy Simulation</h3>
            <p className="text-[10px] text-white/20 uppercase tracking-wider">Run simulation to begin</p>
          </div>
        </div>
        <div className="h-[300px] flex items-center justify-center text-white/15">
          <div className="text-center">
            <AlertCircle className="w-10 h-10 mx-auto mb-2 opacity-20" />
            <p className="text-xs uppercase tracking-wider">No simulation data available</p>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="relative">
      <div className="p-5 pb-4 flex items-center justify-between flex-wrap gap-3">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 bg-white/[0.04] rounded-xl flex items-center justify-center border border-white/[0.06]">
            <Activity className="w-4 h-4 text-[#e10600]/60" />
          </div>
          <div>
            <h3 className="text-sm font-bold text-white/70">Strategy Simulation</h3>
            <p className="text-[10px] text-white/20 uppercase tracking-wider">
              {activeStrategies.length > 0 ? `Comparing ${activeStrategies.length} strategies` : 'Lap time comparison'}
            </p>
          </div>
        </div>

        <div className="flex gap-2 flex-wrap">
          {activeStrategies.map((strat) => (
            <div key={strat.key} className="flex items-center gap-2 px-2.5 py-1 bg-white/[0.03] rounded-lg border border-white/[0.05]">
              <div className="w-2 h-2 rounded-full" style={{ backgroundColor: strat.color }} />
              <span className="text-[10px] text-white/30 uppercase tracking-wider">{strat.name}</span>
            </div>
          ))}
          {predictions && predictions.length > 0 && (
            <div className="flex items-center gap-2 px-2.5 py-1 bg-white/[0.03] rounded-lg border border-white/[0.08] border-dashed">
              <div className="w-2 h-2 rounded-full bg-white/30" />
              <span className="text-[10px] text-white/20 uppercase tracking-wider">Prediction</span>
            </div>
          )}
        </div>
      </div>

      <div className="px-5 pb-2">
        <div className="h-[300px] min-w-[600px]">
          <ResponsiveContainer width="100%" height="100%">
          <ComposedChart data={chartData} margin={{ top: 10, right: 10, left: 0, bottom: 0 }}>
            <defs>
              {activeStrategies.map((strat, idx) => (
                <linearGradient key={strat.key} id={`gradient${idx}`} x1="0" y1="0" x2="0" y2="1">
                  <stop offset="5%" stopColor={strat.color} stopOpacity={0.2}/>
                  <stop offset="95%" stopColor={strat.color} stopOpacity={0}/>
                </linearGradient>
              ))}
            </defs>

            <CartesianGrid strokeDasharray="3 3" stroke="rgba(255,255,255,0.04)" />

            <XAxis 
              dataKey="lap" 
              stroke="rgba(255,255,255,0.1)" 
              fontSize={10}
              tickLine={false}
              axisLine={false}
            />

            <YAxis 
              stroke="rgba(255,255,255,0.1)" 
              fontSize={10}
              tickLine={false}
              axisLine={false}
              domain={yDomain}
              tickFormatter={(value) => `${typeof value === 'number' ? value.toFixed(0) : value}`}
            />

            <Tooltip content={<CustomTooltip />} />

            {currentLap > 0 && (
              <ReferenceLine 
                x={currentLap} 
                stroke="#e10600" 
                strokeDasharray="4 4"
                strokeWidth={1.5}
                label={{ 
                  value: `L${currentLap}`, 
                  fill: '#e10600', 
                  fontSize: 9,
                  position: 'insideTopLeft'
                }}
              />
            )}

            {pitStops?.map((stop, idx) => (
              <ReferenceLine 
                key={idx}
                x={stop.lap || stop} 
                stroke="#fbbf24" 
                strokeDasharray="3 3"
                strokeWidth={1}
                label={{ 
                  value: 'PIT', 
                  fill: '#fbbf24', 
                  fontSize: 9,
                  position: 'insideTopRight'
                }}
              />
            ))}

            {activeStrategies.map((strat, idx) => (
              <Line
                key={strat.key}
                type="monotone"
                dataKey={strat.key}
                stroke={strat.color}
                strokeWidth={strat.width}
                strokeDasharray={strat.dashArray}
                dot={false}
                activeDot={{ r: 4, strokeWidth: 2, stroke: '#fff' }}
                isAnimationActive={true}
                animationDuration={500}
              />
            ))}

            {predictions && predictions.length > 0 && (
              <Line
                type="monotone"
                dataKey="prediction_player"
                stroke="#ffffff"
                strokeWidth={2}
                strokeDasharray="8 4"
                dot={{ r: 3, fill: '#ffffff', strokeWidth: 0 }}
                name="prediction"
                isAnimationActive={true}
                animationDuration={300}
              />
            )}
          </ComposedChart>
        </ResponsiveContainer>
        </div>
      </div>

      {activeStrategies.length > 0 && chartData.length > 0 && (
        <div className="px-5 pb-4 grid grid-cols-3 gap-2">
          {activeStrategies.slice(0, 3).map((strat) => {
            const lastPoint = chartData[chartData.length - 1];
            const finalTime = lastPoint?.[strat.key];
            return (
              <div key={strat.key} className="bg-white/[0.02] rounded-xl p-3 border border-white/[0.05]">
                <div className="flex items-center gap-2 mb-1">
                  <div className="w-1.5 h-1.5 rounded-full" style={{ backgroundColor: strat.color }} />
                  <span className="text-[10px] text-white/25 uppercase tracking-wider">{strat.name}</span>
                </div>
                <div className="text-base font-bold font-mono text-white/70">
                  {finalTime ? <AnimatedValue value={((finalTime * chartData.length) / 60)} precision={1} suffix="m" /> : '--'}
                </div>
                <div className="text-[9px] text-white/15 uppercase tracking-wider">
                  Est. race time
                </div>
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
};

export default memo(SimulationChart);

// Elite Motorsport Strategy Command Interface (Dynamic Evolution)
// This component replaces the generic intelligence panel with a pit-wall-style command console.
// It prioritises visual hierarchy, urgency, and decision-making flow while actively
// reacting to live race state changes from RaceContext.

import React, { memo, useMemo, useEffect, useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import {
  Play,
  AlertTriangle,
  CheckCircle,
  XCircle,
  Clock,
  Droplet,
  Wind,
  CloudRain,
  Car,
  ArrowRight,
  ChevronRight,
  ArrowLeft,
  Check,
  Zap,
  BadgeInfo,
  BadgeAlert,
  BadgeX,
  Triangle,
  Calendar,
  Loader2,
  Crosshair
} from 'lucide-react';
import { useRace } from '../../context/RaceContext';

/* ----------------------------------------------------------
   Dynamic Engine Logic
   ---------------------------------------------------------- */

const useDynamicStrategyEngine = (strategies, raceState, player, allCompetitors) => {
  return useMemo(() => {
    if (!strategies || strategies.length === 0) return [];

    const { currentLap = 0, totalLaps = 53, safetyCarActive = false, weather = {} } = raceState;
    const isWet = weather.state === 'wet' || weather.state === 'rain';

    // Find rival immediately ahead and behind
    const myPos = player?.position || 0;
    const carAhead = allCompetitors?.find(c => c.position === myPos - 1);
    const carBehind = allCompetitors?.find(c => c.position === myPos + 1);

    return strategies.map((s) => {
      const pits = s.pit_stops || [];
      const tires = s.tires_used?.length ? s.tires_used : ['soft'];
      const nextPitLap = pits.find(p => p > currentLap) || null;
      const lapsToPit = nextPitLap ? nextPitLap - currentLap : 0;

      const tireDeg = player?.tireDegradation || 0;
      const tireAge = player?.tireAge || 0;

      // Determine urgency level
      let urgency = 'normal';
      let actionText = s.type === 'aggressive' ? 'MAINTAIN PACE' : 'STAY OUT';

      if (safetyCarActive) {
        urgency = 'critical';
        actionText = 'BOX UNDER SC';
      } else if (lapsToPit > 0 && lapsToPit <= 2) {
        urgency = 'critical';
        actionText = 'PIT THIS LAP';
      } else if (tireDeg > 75 || isWet) {
        urgency = 'warning';
        actionText = isWet ? 'PREPARE INTERS' : 'TYRE CLIFF';
      } else if (carAhead && (player?.gapToLeader || 0) < 1.5 && lapsToPit <= 5) {
        urgency = 'warning';
        actionText = 'PREPARE UNDERCUT';
      }

      if (s.type !== strategies[0]?.type) {
        urgency = 'normal'; // secondary strategies are always normal
      }

      // Build timeline phases
      const phases = [];
      let start = 1;
      pits.forEach((lap, idx) => {
        const end = lap - 1;
        phases.push({ from: start, to: end, type: tires[idx] || 'soft', label: idx === 0 ? 'PUSH' : 'MANAGE' });
        start = lap;
      });
      phases.push({ from: start, to: totalLaps, type: tires[pits.length] || 'soft', label: 'ATTACK' });

      // Generate dynamic intelligence bullets
      const bullets = [];

      // Threat / Risk bullets
      if (tireDeg > 70) bullets.push({ type: 'risk', text: `Tire cliff approaching (${Math.round(tireDeg)}% deg).` });
      if (carBehind && carBehind.lap_time < (player?.lapTime || 999)) {
        bullets.push({ type: 'risk', text: `P${carBehind.position} is closing gap rapidly.` });
      }

      // Opportunity bullets
      if (carAhead && (player?.gapToLeader || 0) < 2.0) {
        bullets.push({ type: 'opportunity', text: `Traffic ahead: Undercut vulnerability high.` });
      }
      if (safetyCarActive) {
        bullets.push({ type: 'opportunity', text: `Free pit stop window open under SC.` });
      }

      // Environment bullets
      if (isWet) bullets.push({ type: 'environment', text: `Track conditions deteriorating.` });
      if (weather.state === 'dry' && tireAge > 10) bullets.push({ type: 'environment', text: `Track evolution stabilizing tyre temps.` });

      // Fallbacks if no dynamic events
      if (bullets.length === 0) {
        bullets.push({ type: 'opportunity', text: 'Clean air opportunity available.' });
        bullets.push({ type: 'environment', text: 'Stable race conditions.' });
      }

      // Dynamic decision tree rules
      const rules = [];
      if (safetyCarActive) rules.push({ condition: 'Safety Car ACTIVE', action: 'Execute free pit stop now.' });
      else rules.push({ condition: `Safety Car before lap ${pits[0] || 20}`, action: 'Switch to alternate strategy.' });

      if (isWet) rules.push({ condition: 'Rain intensity increases', action: 'Extend wet stint.' });
      else rules.push({ condition: 'Rain probability > 40%', action: 'Delay planned pit stop.' });

      // Dynamic confidence evolution
      let baseConf = s.confidence || (s.type === 'conservative' ? 88 : 82);
      if (isWet) baseConf -= 10;
      if (safetyCarActive) baseConf -= 15;
      baseConf += (currentLap / totalLaps) * 10; // confidence grows over time
      baseConf = Math.min(Math.max(baseConf, 0), 100);

      const breakdown = {
        model_confidence: Math.round(baseConf),
        traffic_certainty: Math.round(100 - (allCompetitors?.length || 20) * 1.5),
        weather_stability: isWet ? 45 : 90,
        tyre_prediction: Math.round(100 - (tireDeg * 0.3)),
      };

      const primary = {
        action: actionText,
        gain: s.advantage ?? 0,
        expiresInLaps: lapsToPit,
        confidence: baseConf,
        urgency,
      };

      return { ...s, phases, bullets, rules, breakdown, primary };
    });
  }, [strategies, raceState, player, allCompetitors]);
};


